sm get-map --json 2>&1 | python3 -c "
import json, sys, collections

data = json.loads(sys.stdin.read())
systems_list = data['result']['systems']
systems = {s['system_id']: s for s in systems_list}

# Find bluerift and procyon
bluerift_id = None
procyon_id = None
for sid, s in systems.items():
    name = s.get('name','').lower()
    if 'bluerift' in name or ('blue' in name and 'rift' in name) or 'fading' in name:
        bluerift_id = sid
        print('BLUERIFT:', sid, s.get('name'))
    if 'procyon' in name:
        procyon_id = sid
        print('PROCYON:', sid, s.get('name'))

if not bluerift_id:
    print('Bluerift not found. Searching...')
    for sid, s in systems.items():
        if 'blue' in s.get('name','').lower():
            print(' ', sid, s.get('name'))

# BFS from bluerift to procyon
if bluerift_id and procyon_id:
    from collections import deque
    queue = deque([(bluerift_id, [bluerift_id])])
    visited = {bluerift_id}
    while queue:
        cur, path = queue.popleft()
        if cur == procyon_id:
            print('ROUTE:', ' -> '.join(path))
            print('HOPS:', len(path)-1)
            break
        for neighbor in systems.get(cur, {}).get('connections', []):
            if neighbor not in visited:
                visited.add(neighbor)
                queue.append((neighbor, path + [neighbor]))
" 2>&1
